const TEMPLATE_FAMILY_REGISTRY = new Map([
  ["construction_template", "Temporary classification for bounded, constrained, or vocabulary/surface-anchored templates that are not yet fully POS-general."],
  ["generative_template", "Fully pattern-based template intended to apply to new vocabulary that exposes the same generated slots."],
]);

const PARSER_DECISION_LABEL_POLICY = Object.freeze({
  purpose: "standardize_labels_used_by_active_parser_decisions",
  template_family_boundary: "preserve_construction_template_vs_generative_template_until_all_grammar_is_generative",
  construction_template: "bounded_or_vocabulary_anchored_template_not_yet_fully_pos_general",
  generative_template: "slot_or_pos_pattern_template_reusable_for_new_vocabulary",
  eventual_target: "all productive grammar should become generative_template once the parser can target POS/slots rather than individual vocabulary",
});

function templateFamilyForDefinition(template = {}) {
  if (template.template_family && TEMPLATE_FAMILY_REGISTRY.has(template.template_family)) return template.template_family;
  const constraints = template.constraints || {};
  const hasSurfaceConstraint = Boolean(
    constraints.slot_surface_in ||
    constraints.slot_surface_not_in ||
    constraints.first_node_must_have_surface
  );
  const hasChildOverride = Boolean(
    template.child_parser_inactive_overrides && Object.keys(template.child_parser_inactive_overrides).length
  );
  const note = String(template.note || "");
  const boundedLanguage = /\b(bounded|controlled|constrained|reviewed|closed-list|formula|protected|surface-specific)\b/i.test(note);
  return hasSurfaceConstraint || hasChildOverride || boundedLanguage ? "construction_template" : "generative_template";
}


// Registry-clean slots are still parser/internal labels. The learner-facing
// hover layer should expose only broad grammar hints and keep implementation or
// frame-specific slots such as stance_holder / opinion_topic / reported_content
// inside diagnostics.
const LEARNER_DISPLAY_SLOT_NAMES = new Set([
  "action_verb",
  "beneficiary",
  "classifier",
  "degree",
  "demonstrative",
  "head_noun",
  "location",
  "main_verb",
  "modal",
  "modifier",
  "negator",
  "nominal_linker",
  "np",
  "object",
  "particle",
  "predicate",
  "quantity",
  "subject",
  "time",
  "topic",
  "vp",
  "wh_determiner",
]);

const LEARNER_DISPLAY_SLOT_LABELS = {
  classifier: "measure_word",
  quantity: "how",
};

function learnerDisplaySlotLabel(slot) {
  return LEARNER_DISPLAY_SLOT_LABELS[slot] || slot;
}

function learnerDisplaySlots(slots = []) {
  return cleanSlots(slots)
    .filter((slot) => LEARNER_DISPLAY_SLOT_NAMES.has(slot))
    .map(learnerDisplaySlotLabel);
}

function internalOnlySlots(slots = []) {
  return cleanSlots(slots)
    .filter((slot) => !LEARNER_DISPLAY_SLOT_NAMES.has(slot));
}

function normalizeLearnerLabel(label, surface = "", syntax = "") {
  if (LEARNER_ROLE_LABELS.has(label)) return label;
  if (label === "classifier") return "measure_word";
  if (label === "stance") {
    if (surface === "鍾意") return "like";
    if (syntax.includes("suggestion_marker") || syntax.includes("possibility") || syntax.includes("seeming") || syntax.includes("should")) return "func";
    return "doing";
  }
  return "neutral";
}

function slotNameRegistryIssue(slot) {
  if (typeof slot !== "string") return "slot_not_string";
  if (!/^[a-z][a-z0-9_]*$/.test(slot)) return "slot_not_snake_case";
  if (SLOT_NAME_DISALLOWED_PREFIXES.some((pattern) => pattern.test(slot))) return "implementation_phase_marker_in_slot";
  return "";
}

function isCleanSlotName(slot) {
  return !slotNameRegistryIssue(slot);
}

function cleanSlots(slots = []) {
  return [...new Set((slots || []).filter(isCleanSlotName))].sort();
}

function learnerRoleRegistryRows(analysis) {
  return flattenNodes(analysis.nodes)
    .filter((row) => row.kind === "token")
    .filter((row) => !LEARNER_ROLE_LABELS.has(row.role || ""))
    .map((row) => ({
      surface: row.surface,
      role: row.role || "",
      syntax: row.syntax || "",
      parent: row.parent || "",
      reason: "Token learner role is outside the controlled learner-role registry.",
    }));
}

function slotNameRegistryRows(analysis) {
  const rows = [];
  for (const row of flattenNodes(analysis.nodes)) {
    for (const slot of row.slots || []) {
      const issue = slotNameRegistryIssue(slot);
      if (!issue) continue;
      rows.push({
        surface: row.surface || "",
        kind: row.kind || "",
        construction: row.type || "",
        role: row.role || "",
        slot,
        issue,
        reason: issue === "implementation_phase_marker_in_slot"
          ? "Phase/custom implementation markers belong in trace or feature bundles, not slot names."
          : "Slot names must be lower snake_case registry labels, not construction names or display labels.",
      });
    }
  }
  return rows;
}

function constructionLabelRegistryRows(analysis) {
  return flattenNodes(analysis.nodes)
    .filter((row) => row.kind === "construction")
    .map((row) => {
      const construction = row.type || "";
      const retiredReason = RETIRED_CONSTRUCTION_LABEL_REGISTRY.get(construction);
      if (retiredReason) {
        return {
          surface: row.surface || "",
          construction,
          issue: "retired_or_over_specific_construction_label",
          reason: retiredReason,
          policy: CONSTRUCTION_LABEL_POLICY,
        };
      }
      if (!CONSTRUCTION_LABEL_REGISTRY.has(construction)) {
        return {
          surface: row.surface || "",
          construction,
          issue: "construction_label_outside_controlled_registry",
          reason: "Construction label is outside the controlled construction-label registry. New labels require grammar evidence first; explicit approval is required only for useful project-specific labels that lack external or recurring grammar justification.",
          policy: CONSTRUCTION_LABEL_POLICY,
        };
      }
      return null;
    })
    .filter(Boolean);
}

function parserDecisionLabelRegistryRows(analysis) {
  const rows = [];
  for (const row of flattenNodes(analysis.nodes)) {
    const trace = row.trace || {};
    const kind = trace.kind || "";
    if (kind && !PARSER_DECISION_TRACE_KIND_REGISTRY.has(kind)) {
      rows.push({
        surface: row.surface || "",
        kind: row.kind || "",
        construction: row.type || "",
        trace_kind: kind,
        issue: "parser_decision_trace_kind_outside_registry",
        reason: "Trace kind is used in parser diagnostics or parser decisions but is outside the controlled parser-decision trace registry.",
        policy: PARSER_DECISION_LABEL_POLICY,
      });
    }
    const templateFamily = trace.template_family || "";
    if (templateFamily && !TEMPLATE_FAMILY_REGISTRY.has(templateFamily)) {
      rows.push({
        surface: row.surface || "",
        kind: row.kind || "",
        construction: row.type || "",
        template_family: templateFamily,
        issue: "template_family_outside_registry",
        reason: "Template family must remain one of the controlled names while construction_template and generative_template are still distinct.",
        policy: PARSER_DECISION_LABEL_POLICY,
      });
    }
  }
  return rows;
}

function registryAuditSummary(analysis) {
  const invalidLearnerRoles = learnerRoleRegistryRows(analysis);
  const invalidSlotNames = slotNameRegistryRows(analysis);
  const invalidConstructionLabels = constructionLabelRegistryRows(analysis);
  const invalidParserDecisionLabels = parserDecisionLabelRegistryRows(analysis);
  return {
    status: invalidLearnerRoles.length || invalidSlotNames.length || invalidConstructionLabels.length || invalidParserDecisionLabels.length ? "WARN" : "PASS",
    learner_role_registry_status: invalidLearnerRoles.length ? "WARN" : "PASS",
    slot_name_registry_status: invalidSlotNames.length ? "WARN" : "PASS",
    construction_label_registry_status: invalidConstructionLabels.length ? "WARN" : "PASS",
    parser_decision_label_registry_status: invalidParserDecisionLabels.length ? "WARN" : "PASS",
    invalid_learner_role_count: invalidLearnerRoles.length,
    invalid_slot_name_count: invalidSlotNames.length,
    invalid_construction_label_count: invalidConstructionLabels.length,
    invalid_parser_decision_label_count: invalidParserDecisionLabels.length,
    invalid_learner_roles: invalidLearnerRoles,
    invalid_slot_names: invalidSlotNames,
    invalid_construction_labels: invalidConstructionLabels,
    invalid_parser_decision_labels: invalidParserDecisionLabels,
    parser_decision_label_policy: PARSER_DECISION_LABEL_POLICY,
  };
}

function learnerDisplayAuditRows(analysis) {
  return flattenNodes(analysis.nodes)
    .map((row) => {
      const hidden = internalOnlySlots(row.slots || []);
      return {
        surface: row.surface || "",
        kind: row.kind || "",
        construction: row.type || "",
        role: row.role || "",
        learner_display_slots: learnerDisplaySlots(row.slots || []),
        hidden_internal_slots: hidden,
      };
    })
    .filter((row) => row.hidden_internal_slots.length);
}

function learnerDisplayAuditSummary(analysis) {
  const rows = learnerDisplayAuditRows(analysis);
  const hiddenCounts = {};
  for (const row of rows) {
    for (const slot of row.hidden_internal_slots) hiddenCounts[slot] = (hiddenCounts[slot] || 0) + 1;
  }
  return {
    status: "PASS",
    learner_display_slot_status: "PASS",
    policy: "Parser/internal slots remain available in diagnostics. Hover titles may expose concise role/syntax metadata plus learner glosses, but raw slots and internal counts remain diagnostics-only.",
    nodes_with_hidden_internal_slots: rows.length,
    hidden_internal_slot_reference_count: Object.values(hiddenCounts).reduce((sum, count) => sum + count, 0),
    hidden_internal_slot_counts: hiddenCounts,
    sample_hidden_internal_slot_rows: rows.slice(0, 12),
  };
}

function lexicalizedStativeRegistryKind(surface) {
  const entry = TOKEN_LEXICON[surface] || {};
  const label = entry.label || "neutral";
  const syntax = entry.syntax || "";
  const features = inferTokenFeatures(surface, { ...entry, label, syntax }, { label, syntax });
  const bundle = featureBundleFor(surface, { ...entry, label, syntax }, features, []);
  const lexicalizationType = getLexicalizationType(bundle);
  if (lexicalizationType === "negative_lexicalized_stative") return "negative_lexicalized_stative_registry";
  if (lexicalizationType === "lexicalized_stative") return "lexicalized_stative_registry";
  return "";
}

function transparentClassifierObjectParts(surface) {
  const phrase = String(surface || "");
  const entry = TOKEN_LEXICON[phrase] || {};
  const syntax = String(entry.syntax || "");
  if (!syntax.split(/\s+/u).includes("classifier_object_np")) return null;

  const classifier = Object.keys(TOKEN_LEXICON)
    .filter((candidate) => candidate.length < phrase.length && phrase.startsWith(candidate))
    .filter((candidate) => (TOKEN_LEXICON[candidate] || {}).label === "measure_word")
    .sort((a, b) => b.length - a.length || a.localeCompare(b))[0];
  if (!classifier) return null;

  const head = phrase.slice(classifier.length);
  const headEntry = TOKEN_LEXICON[head] || {};
  if (!head || !["what", "who", "where"].includes(headEntry.label || "")) return null;
  return { classifier, head };
}

function shouldForceCompositional(surface) {
  // Registry-backed lexicalized statives win over forced compositional splitting.
  // This prevents accidental future regressions such as adding 好食 to
  // COMPOSITIONAL_LEXICAL_PHRASES and losing the lexicalized predicate.
  if (lexicalizedStativeRegistryKind(surface)) return false;

  // Any lexical reference entry explicitly typed as classifier_object_np must
  // remain transparent when both the classifier and noun head have independent
  // lexical evidence. This generalizes the accepted classifier-role doctrine:
  // 本書 must expose 本:measure_word + 書:what rather than collapse to one what token.
  if (transparentClassifierObjectParts(surface)) return true;
  return COMPOSITIONAL_LEXICAL_PHRASES.has(surface);
}

const ALL_LEXICON_TERMS = Object.keys(TOKEN_LEXICON)
  .filter((surface) => !PRODUCTIVE_VO[surface])
  .sort((a, b) => b.length - a.length || a.localeCompare(b));

const LEXICON_TERMS = ALL_LEXICON_TERMS
  .filter((surface) => !shouldForceCompositional(surface))
  .sort((a, b) => b.length - a.length || a.localeCompare(b));

const LEXICALIZED_STATIVE_SELECTION_WEIGHT = 10000;

function lexicalCandidateScore(surface) {
  const registryKind = lexicalizedStativeRegistryKind(surface);
  const registryScore = registryKind ? LEXICALIZED_STATIVE_SELECTION_WEIGHT : 0;
  return registryScore + surface.length;
}

function followingLexicalizedStativeAfterChoice(choice, rest) {
  const afterChoice = String(rest || "").slice(String(choice || "").length);
  if (!afterChoice) return null;
  const following = ALL_LEXICON_TERMS
    .filter((surface) => afterChoice.startsWith(surface) && lexicalizedStativeRegistryKind(surface))
    .sort((a, b) => b.length - a.length || a.localeCompare(b))[0];
  if (!following) return null;
  return { surface: following, registry_kind: lexicalizedStativeRegistryKind(following) };
}

function lexicalSelectionReason(choice, candidates, excluded, rest = "") {
  const registryKind = lexicalizedStativeRegistryKind(choice);
  const competingRegistry = candidates
    .filter((surface) => surface !== choice && lexicalizedStativeRegistryKind(surface))
    .map((surface) => lexicalizedStativeRegistryKind(surface));
  const hasLongerExcluded = excluded.some((item) => item.length > choice.length);
  const followingRegistry = followingLexicalizedStativeAfterChoice(choice, rest);

  if (registryKind) {
    return `${registryKind} candidate wins over compositional or shorter candidates by lexicalized-stative selection scoring.`;
  }
  if (hasLongerExcluded) {
    return "Chosen after longer forced-compositional phrase was excluded so learner-visible internal structure can remain available.";
  }
  if (followingRegistry && choice === "好") {
    return `Chosen as degree modifier before following ${followingRegistry.registry_kind} candidate ${followingRegistry.surface}; learner-visible composition remains available.`;
  }
  if (competingRegistry.length) {
    return "Chosen by score/length after comparing with registry-backed candidates.";
  }
  return "Chosen by ordinary lexical lookup; no registry-backed lexicalized stative candidate applies at this cursor.";
}

function lexicalSelectionDecision(rest, candidates, excluded, choice) {
  return {
    rule: "prefer_lexicalized_stative_over_compositional_when_registry_evidence_exists",
    chosen: choice,
    chosen_registry_kind: lexicalizedStativeRegistryKind(choice),
    chosen_score: lexicalCandidateScore(choice),
    reason: lexicalSelectionReason(choice, candidates, excluded, rest),
    candidates: candidates.map((surface) => ({
      surface,
      registry_kind: lexicalizedStativeRegistryKind(surface),
      score: lexicalCandidateScore(surface),
      forced_compositional: false,
    })),
    excluded_compositional_candidates: excluded.map((surface) => ({
      surface,
      registry_kind: lexicalizedStativeRegistryKind(surface),
      forced_compositional: true,
      reason: transparentClassifierObjectParts(surface)
        ? "Explicit classifier_object_np reference entry split into an independently evidenced classifier plus noun head."
        : "Listed in COMPOSITIONAL_LEXICAL_PHRASES and not protected by lexicalized-stative registry evidence.",
    })),
    rest_preview: rest.slice(0, 12),
  };
}

function selectionDecisionForSurface(surface, rest = surface) {
  const candidates = LEXICON_TERMS.filter((candidate) => rest.startsWith(candidate));
  const excluded = ALL_LEXICON_TERMS
    .filter((candidate) => rest.startsWith(candidate) && shouldForceCompositional(candidate));
  const fallbackCandidates = candidates.includes(surface) ? candidates : [surface, ...candidates];
  return lexicalSelectionDecision(rest, fallbackCandidates, excluded, surface);
}

function selectLexiconTerm(rest) {
  const candidates = LEXICON_TERMS.filter((surface) => rest.startsWith(surface));
  if (!candidates.length) return null;

  const excluded = ALL_LEXICON_TERMS
    .filter((surface) => rest.startsWith(surface) && shouldForceCompositional(surface));

  candidates.sort((a, b) => {
    const scoreDiff = lexicalCandidateScore(b) - lexicalCandidateScore(a);
    if (scoreDiff) return scoreDiff;
    const lengthDiff = b.length - a.length;
    if (lengthDiff) return lengthDiff;
    return a.localeCompare(b);
  });

  const surface = candidates[0];
  return {
    surface,
    registry_kind: lexicalizedStativeRegistryKind(surface),
    score: lexicalCandidateScore(surface),
    candidate_count: candidates.length,
    selection_decision: lexicalSelectionDecision(rest, candidates, excluded, surface),
  };
}
